var RSS_ONEPAGER="<!DOCTYPE html>\n<html lang=\"de\">\n<head>\n<meta charset=\"utf-8\"/>\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"/>\n<title>RSS \u2013 One-Pager</title>\n<style>\n  :root{\n    --ink:#141414; --orange:#DE6A2C; --muted:#6f6f6f; --line:#e4e4e4; --box:#faf5f0;\n    --font:'Helvetica Neue',Helvetica,Arial,sans-serif;\n  }\n  *{box-sizing:border-box;margin:0;padding:0}\n  html,body{background:#f2f2f2}\n  body{font-family:var(--font);color:var(--ink);-webkit-font-smoothing:antialiased;line-height:1.5}\n  .page{width:210mm;min-height:297mm;margin:16px auto;background:#fff;padding:20mm 18mm;\n    box-shadow:0 6px 30px rgba(0,0,0,.12)}\n  .logo{height:52px;width:auto;display:block;margin-bottom:22px}\n  .eyebrow{font-size:10.5px;font-weight:800;letter-spacing:.28em;text-transform:uppercase;color:var(--orange)}\n  h1{font-size:26px;font-weight:800;letter-spacing:-.4px;line-height:1.12;margin:6px 0 10px}\n  .lead{font-size:14px;color:#333;max-width:52em}\n  .lead b{color:var(--ink)}\n  hr{border:0;border-top:1.5px solid var(--ink);margin:18px 0}\n  .cols{display:flex;gap:34px;margin-top:20px}\n  .cols .col{flex:1}\n  h3{font-size:14px;font-weight:800;margin-bottom:10px}\n  ul{list-style:none}\n  li{font-size:13px;padding-left:18px;position:relative;margin-bottom:7px;color:#2a2a2a}\n  li::before{content:\"\u25b8\";position:absolute;left:0;color:var(--orange);font-weight:800}\n  .partnerbox{border:1px solid #ecd9c9;background:var(--box);border-left:4px solid var(--orange);\n    padding:16px 18px;margin:22px 0}\n  .partnerbox .eyebrow{letter-spacing:.24em}\n  .partnerbox h3{font-size:15px;margin:5px 0 10px}\n  .partnerbox li::before{content:\"\u25cf\";font-size:8px;top:5px}\n  .partnerbox li b{color:var(--ink)}\n  .pillars{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin:24px 0 6px}\n  .pillar{border-top:2px solid var(--line);padding-top:10px}\n  .pillar .num{font-size:22px;font-weight:800;color:var(--orange);line-height:1}\n  .pillar .t{font-size:13px;font-weight:800;margin:6px 0 3px}\n  .pillar .d{font-size:11.5px;color:var(--muted);line-height:1.4}\n  .foot{display:flex;gap:34px;border-top:1.5px solid var(--ink);margin-top:26px;padding-top:14px}\n  .foot .col{flex:1}\n  .foot .eyebrow{letter-spacing:.2em;margin-bottom:6px}\n  .foot b{font-size:13px}\n  .foot .info{font-size:12px;color:#444;margin-top:3px;line-height:1.5}\n  .cta-btn{display:inline-block;margin-top:10px;background:var(--orange);color:#fff;text-decoration:none;\n    font-weight:800;font-size:12.5px;letter-spacing:.05em;text-transform:uppercase;padding:10px 18px}\n  .cta-url{font-size:10.5px;color:var(--muted);margin-top:5px;word-break:break-all}\n  .print-hint{max-width:210mm;margin:0 auto 20px;text-align:center;font-size:12px;color:#888}\n  .print-hint button{background:var(--ink);color:#fff;border:0;padding:9px 16px;font-weight:800;\n    text-transform:uppercase;letter-spacing:.05em;cursor:pointer;font-family:var(--font);margin-left:8px}\n  @media print{\n    html,body{background:#fff}\n    .page{width:auto;min-height:auto;margin:0;padding:14mm 15mm;box-shadow:none}\n    .print-hint{display:none}\n    @page{size:A4;margin:0}\n  }\n</style>\n</head>\n<body>\n\n<div class=\"page\">\n  <img class=\"logo\" src=\"data:image/png;base64,\" alt=\"RSS \u2013 Recycling Solution Service\"/>\n\n  <div class=\"eyebrow\">Abfallmanagement ohne Interessenkonflikt</div>\n  <h1>Neutraler Partner f\u00fcr Gewerbe,<br>Wohnungswirtschaft und Investoren</h1>\n  <p class=\"lead\">Wir pr\u00fcfen Entsorgungsvertr\u00e4ge, b\u00fcndeln Liegenschaften und handeln bessere Konditionen\n    aus \u2013 mit regionalen Entsorgungspartnern. <b>Ohne eigenen Fuhrpark. Mit einem Ansprechpartner.</b></p>\n\n  <div class=\"cols\">\n    <div class=\"col\">\n      <h3>Was wir machen</h3>\n      <ul>\n        <li>Bestandsanalyse: Vertr\u00e4ge, Beh\u00e4lter, Rhythmen, Kosten</li>\n        <li>Optimierung im Bestand oder per Wechsel</li>\n        <li>Laufendes Vertrags- und Rechnungsmanagement</li>\n        <li>ESG- &amp; CO\u2082-Reporting, CSRD-/GdW-tauglich</li>\n      </ul>\n    </div>\n    <div class=\"col\">\n      <h3>F\u00fcr wen</h3>\n      <ul>\n        <li>Hausverwaltungen &amp; Wohnungsunternehmen</li>\n        <li>Immobilieninvestoren &amp; Asset Manager</li>\n        <li>Gewerbe, Gastronomie, Handel</li>\n        <li>Genossenschaften und Quartiersinitiativen</li>\n      </ul>\n    </div>\n  </div>\n\n  <div class=\"partnerbox\">\n    <div class=\"eyebrow\">Ihr Vorteil</div>\n    <h3>Was Sie davon haben</h3>\n    <ul>\n      <li><b>Weniger Kosten:</b> bessere Konditionen durch geb\u00fcndeltes Volumen \u2013 meist g\u00fcnstiger als heute, ohne dass Sie etwas umstellen m\u00fcssen.</li>\n      <li><b>Weniger Aufwand:</b> ein Ansprechpartner f\u00fcr Vertr\u00e4ge, Beh\u00e4lter, Rhythmen, Reklamationen und Rechnungen.</li>\n      <li><b>Neutral &amp; unabh\u00e4ngig:</b> kein eigener Fuhrpark, kein Interessenkonflikt \u2013 wir handeln in Ihrem Interesse.</li>\n      <li><b>Transparenz &amp; ESG:</b> liegenschaftsscharfe Daten und CO\u2082-Reporting, CSRD-/GdW-tauglich.</li>\n    </ul>\n  </div>\n\n  <div class=\"pillars\">\n    <div class=\"pillar\"><div class=\"num\">01</div><div class=\"t\">Neutral</div><div class=\"d\">Kein eigener Fuhrpark \u2013 kein Interessenkonflikt.</div></div>\n    <div class=\"pillar\"><div class=\"num\">02</div><div class=\"t\">Geb\u00fcndelt</div><div class=\"d\">Einkaufsvolumen vieler Liegenschaften.</div></div>\n    <div class=\"pillar\"><div class=\"num\">03</div><div class=\"t\">Zentral</div><div class=\"d\">Ein Ansprechpartner f\u00fcr alles.</div></div>\n    <div class=\"pillar\"><div class=\"num\">04</div><div class=\"t\">Transparent</div><div class=\"d\">Liegenschaftsscharfe Daten und CO\u2082.</div></div>\n  </div>\n\n  <div class=\"foot\">\n    <div class=\"col\">\n      <div class=\"eyebrow\">Kontakt</div>\n      <b>RSS Recycling Solution Service</b>\n      <div class=\"info\">S\u00f6ren Rohde \u00b7 +49 176 14081987<br>rohde@rss-entsorgung.de \u00b7 rss-entsorgung.de</div>\n    </div>\n    <div class=\"col\">\n      <div class=\"eyebrow\">Ihr n\u00e4chster Schritt</div>\n      <b>Kostenloses M\u00fcll-Audit \u2013 Termin buchen</b>\n      <div class=\"info\">In wenigen Minuten pr\u00fcfen wir Ihre aktuellen Entsorgungskosten \u2013 unverbindlich. Sie sehen schwarz auf wei\u00df, was f\u00fcr Sie drin ist.</div>\n      <a class=\"cta-btn\" href=\"https://calendar.app.google/8aMLyBSo6RnzC26P8\" target=\"_blank\" rel=\"noopener\">\ud83d\udcc5 Termin buchen</a>\n      <div class=\"cta-url\">calendar.app.google/8aMLyBSo6RnzC26P8</div>\n    </div>\n  </div>\n</div>\n\n</body>\n</html>\n";
